#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <stdbool.h>

// generate primes up to limit using simple sieve
static int *basePrimes; // dynamic array of base primes
static int baseCount;

void simpleSieve(int limit) {
    bool *mark = (bool *)malloc((limit + 1) * sizeof(bool));
    for (int i = 0; i <= limit; ++i) mark[i] = true;
    mark[0] = mark[1] = false;
    for (int p = 2; p * p <= limit; ++p) {
        if (mark[p]) {
            for (int i = p * p; i <= limit; i += p)
                mark[i] = false;
        }
    }
    // count primes
    baseCount = 0;
    for (int i = 2; i <= limit; ++i) if (mark[i]) ++baseCount;
    basePrimes = (int *)malloc(baseCount * sizeof(int));
    int idx = 0;
    for (int i = 2; i <= limit; ++i) if (mark[i]) basePrimes[idx++] = i;
    free(mark);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    // pre‑compute base primes up to sqrt(1e9)
    int limit = (int)sqrt(1000000000.0) + 1;
    simpleSieve(limit);
    for (int tc = 0; tc < T; ++tc) {
        long long m, n;
        scanf("%lld %lld", &m, &n);
        int size = (int)(n - m + 1);
        bool *isPrime = (bool *)malloc(size * sizeof(bool));
        for (int i = 0; i < size; ++i) isPrime[i] = true;
        for (int i = 0; i < baseCount; ++i) {
            long long p = basePrimes[i];
            long long start = p * p;
            if (start < m) start = ((m + p - 1) / p) * p;
            for (long long j = start; j <= n; j += p) {
                isPrime[j - m] = false;
            }
        }
        if (m == 1) isPrime[0] = false;
        for (int i = 0; i < size; ++i) {
            if (isPrime[i]) {
                printf("%lld\n", m + i);
            }
        }
        if (tc != T - 1) printf("\n");
        free(isPrime);
    }
    free(basePrimes);
    return 0;
}

