public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        int limit = (int)Math.sqrt(1000000000L) + 1;
        boolean[] mark = new boolean[limit + 1];
        Arrays.fill(mark, true);
        mark[0] = mark[1] = false;
        for (int p = 2; p * p <= limit; ++p) {
            if (mark[p]) {
                for (int i = p * p; i <= limit; i += p) mark[i] = false;
            }
        }
        List<Integer> base = new ArrayList<>();
        for (int i = 2; i <= limit; ++i) if (mark[i]) base.add(i);
        for (int tc = 0; tc < T; ++tc) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long m = Long.parseLong(st.nextToken());
            long n = Long.parseLong(st.nextToken());
            int size = (int)(n - m + 1);
            boolean[] isPrime = new boolean[size];
            Arrays.fill(isPrime, true);
            for (int p : base) {
                long start = 1L * p * p;
                if (start < m) start = ((m + p - 1) / p) * p;
                for (long j = start; j <= n; j += p) {
                    isPrime[(int)(j - m)] = false;
                }
            }
            if (m == 1) isPrime[0] = false;
            for (int i = 0; i < size; ++i) {
                if (isPrime[i]) out.append(m + i).append('\n');
            }
            if (tc != T - 1) out.append('\n');
