import sys, math

def segmented_primes(m, n, base):
    size = n - m + 1
    is_prime = [True] * size
    for p in base:
        start = p * p
        if start < m:
            start = ((m + p - 1) // p) * p
        for j in range(start, n + 1, p):
            is_prime[j - m] = False
    if m == 1:
        is_prime[0] = False
    return [str(m + i) for i, val in enumerate(is_prime) if val]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    # pre‑compute base primes up to sqrt(1e9)
    limit = int(math.isqrt(1000000000)) + 1
    sieve = [True] * (limit + 1)
    sieve[0] = sieve[1] = False
    for i in range(2, int(limit ** 0.5) + 1):
        if sieve[i]:
            step = i
            start = i * i
            sieve[start:limit+1:step] = [False] * ((limit - start) // step + 1)
    base = [i for i, v in enumerate(sieve) if v]
    out_lines = []
    for tc in range(T):
        m = int(next(it)); n = int(next(it))
        out_lines.extend(segmented_primes(m, n, base))
        if tc != T - 1:
            out_lines.append('')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

